#include <stdio.h>
#include <stdlib.h>

int main() {
    int r, g, b;
    scanf("%d %d %d", &r, &g, &b);
    int li[3] = {r, g, b};

    // Sort the array
    for (int i = 0; i < 3; i++) {
        for (int j = i + 1; j < 3; j++) {
            if (li[i] > li[j]) {
                int temp = li[i];
                li[i] = li[j];
                li[j] = temp;
            }
        }
    }

    if (li[2] > 2 * (li[0] + li[1])) {
        printf("%d\n", li[0] + li[1]);
    } else {
        printf("%d\n", (li[0] + li[1] + li[2]) / 3);
    }

    return 0;
}
