#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int r, g, b;
    scanf("%d %d %d", &r, &g, &b);
    int li[3] = {r, g, b};
    qsort(li, 3, sizeof(int), compare);
    if (li[2] > 2 * (li[0] + li[1])) {
        printf("%d", li[0] + li[1]);
    } else {
        printf("%d", (li[0] + li[1] + li[2]) / 3);
    }
    return 0;
}
